1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return an empty grid when given an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a cell alive that has exactly two live neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toEqual(
17	      expect.arrayContaining([[1, 0]])
18	    );
19	  });
20	  it("should keep a cell alive that has exactly three live neighbors (survival)", () => {
21	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
22	    expect(result).toEqual(
23	      expect.arrayContaining([[1, 0]])
24	    );
25	  });
26	  it("should bring a dead cell to life when it has exactly three live neighbors (reproduction)", () => {
27	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
28	    expect(result).toEqual(
29	      expect.arrayContaining([[1, 1]])
30	    );
31	  });
32	  it("should kill a cell that has four live neighbors (overpopulation)", () => {
33	    const result = nextGeneration([[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]]);
34	    expect(result).not.toEqual(
35	      expect.arrayContaining([[1, 1]])
36	    );
37	  });
38	  it.todo("should maintain a block still life (2x2 square) unchanged across a generation");
39	  it.todo("should oscillate a blinker (three cells in a line) to its alternate phase");
40	});
