1	export function nextGeneration(livingCells: [number, number][]): [number, number][] {
2	  if (livingCells.length === 0) return [];
3	
4	  const alive = new Set(livingCells.map(([x, y]) => `${x},${y}`));
5	  const candidates = new Set<string>();
6	
7	  for (const [x, y] of livingCells) {
8	    for (let dx = -1; dx <= 1; dx++) {
9	      for (let dy = -1; dy <= 1; dy++) {
10	        candidates.add(`${x + dx},${y + dy}`);
11	      }
12	    }
13	  }
14	
15	  const result: [number, number][] = [];
16	
17	  for (const key of candidates) {
18	    const [x, y] = key.split(",").map(Number);
19	    let neighbors = 0;
20	    for (let dx = -1; dx <= 1; dx++) {
21	      for (let dy = -1; dy <= 1; dy++) {
22	        if (dx === 0 && dy === 0) continue;
23	        if (alive.has(`${x + dx},${y + dy}`)) neighbors++;
24	      }
25	    }
26	    if (alive.has(key)) {
27	      if (neighbors === 2 || neighbors === 3) result.push([x, y]);
28	    } else {
29	      if (neighbors === 3) result.push([x, y]);
30	    }
31	  }
32	
33	  return result;
34	}
